    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No mention of structured logging for fraud check outcomes (allow/deny/timeout/error)",
        "No logging of DB connection pool utilization or wait times",
        "No correlation IDs or distributed tracing mentioned for end-to-end request tracking",
        "No logging of circuit breaker state transitions (closed→open→half-open)"
      ]
